// ─── Authority Descriptions ───────────────────────────────────────────────────

export const AUTHORITY_DESCRIPTIONS: Record<string, {
  name: string;
  description: string;
  howToUse: string;
}> = {
  "Emotional (Solar Plexus)": { name: "Emocionální autorita", description: "Máte definované centrum Solárního plexu, což znamená, že prožíváte emocionální vlnu. Vaše pravda nikdy není v daném okamžiku — odhaluje se v průběhu času, jak jedete svou emocionální vlnou od výšky k hloubce a zpět.", howToUse: "Nikdy nepřijímejte důležitá rozhodnutí v horku okamžiku, ať se cítíte vysoko nebo nízko. Čekejte na emocionální jasnost — pocit klidného vědění, který přichází poté, co jste prožili celou škálu své emocionální vlny. Přespěte důležitá rozhodnutí. Mantra je: 'V přítomném okamžiku není pravda.'" },
  "Sacral": { name: "Sakrální autorita", description: "Vaše Sakrální centrum je vaší rozhodovací autoritou. Komunikuje skrze střevní reakce — zvuky jako 'uh-huh' (ano) nebo 'uhn-uhn' (ne) a fyzické pocity expanze nebo kontrakce.", howToUse: "Věnujte pozornost své střevní reakci, když vám život přináší příležitosti. Pokládejte si otázky ano/ne a sledujte reakci svého těla. Vaše Sakrální centrum mluví v okamžiku skrze zvuky a fyzické pocity. Důvěřujte počáteční střevní reakci — ví to dříve než vaše mysl." },
  "Splenic": { name: "Slezinová autorita", description: "Vaše centrum Sleziny je vaší rozhodovací autoritou. Komunikuje skrze spontánní intuitivní záblesky — tiché vnitřní vědění o tom, co je pro vás v daném okamžiku zdravé a bezpečné.", howToUse: "Důvěřujte svému prvnímu instinktu. Slezina mluví pouze jednou, tiše a v okamžiku. Je to jemné vědomí, že něco je pro vás správné nebo špatné. Nepřemýšlejte příliš — vaše slezinové vědomí je rychlejší než vaše mysl. Věnujte pozornost spontánním pocitům přitažlivosti nebo odporu." },
  "Ego Manifested": { name: "Ego manifestovaná autorita", description: "Vaše centrum Srdce/Ega je spojeno s Hrdlem, což vám dává autoritu přijímat rozhodnutí na základě toho, co vaše srdce skutečně chce a k čemu se může zavázat.", howToUse: "Naslouchejte tomu, co skutečně chcete a k čemu jste ochotni zavázat svou vůli. Ptejte se sami sebe: 'Je to to, co skutečně chci? Jsem ochoten do toho vložit srdce?' Vaše rozhodnutí by měla vycházet z upřímné touhy a vůle, ne z povinnosti." },
  "Ego Projected": { name: "Ego projektovaná autorita", description: "Vaše centrum Srdce/Ega je vaší autoritou, ale projektuje se skrze centrum G spíše než skrze Hrdlo. Potřebujete slyšet sami sebe mluvit o tom, co chcete, abyste nalezli jasnost.", howToUse: "Mluvte s důvěryhodnými přáteli o svých rozhodnutích a naslouchejte tomu, co z vás vychází. Uslyšíte svou pravdu ve svých vlastních slovech. Věnujte pozornost tomu, co vzrušuje vaše srdce a k čemu se skutečně cítíte ochotni zavázat." },
  "Self-Projected": { name: "Autorita projektovaného Já", description: "Vaše centrum G (Já) je vaší rozhodovací autoritou. Nacházíte jasnost tím, že slyšíte sami sebe mluvit o své identitě a směru.", howToUse: "Mluvte s důvěryhodnými lidmi o svých rozhodnutích a naslouchejte tomu, co říkáte. Vaše pravda se vynořuje skrze váš vlastní hlas. Věnujte pozornost výrokům o identitě ('Jsem...') a směru ('Chystám se...'). Vaše rozhodnutí by měla být v souladu s vaším smyslem pro sebe." },
  "Mental (Outer Authority)": { name: "Mentální/environmentální autorita", description: "Nemáte žádnou vnitřní autoritu pod Hrdlem. Váš rozhodovací proces zahrnuje mluvení o věcech s ostatními a pobývání ve správném prostředí.", howToUse: "Diskutujte svá rozhodnutí s různými lidmi a v různých prostředích. Všimněte si, jak různá místa a lidé ovlivňují vaši jasnost. Jste navrženi být ozvučnou deskou pro ostatní a na oplátku nacházíte svou vlastní jasnost skrze dialog a prostředí." },
  "Lunar (No Inner Authority)": { name: "Lunární autorita", description: "Jako Reflektor bez definovaných center je vaše autorita spojena s 28denním cyklem Měsíce. Potřebujete celý lunární cyklus k získání jasnosti v důležitých rozhodnutích.", howToUse: "Pro důležitá rozhodnutí čekejte celý 28denní lunární cyklus. Během této doby diskutujte rozhodnutí s různými lidmi a sledujte, jak se vaše perspektiva den za dnem mění. Veďte si měsíční deník. Po celém cyklu budete mít jasný pocit, co je pro vás správné." },
};

